+    // CLI Commands
+    // ========================================================================
+
+    api.registerCli(
+      ({ program }) => {
+        const memory = program
+          .command("ltm")
+          .description("Long-term memory plugin commands");
+
+        memory
+          .command("list")
+          .description("List memories")
+          .action(async () => {
+            const count = await db.count();
+            console.log(`Total memories: ${count}`);
+          });
